/**
* AI Provider Factory and Model Registry
*
* Multi-provider support via Vercel AI SDK. Adapted from fit-decision's
* provider pattern, simplified for Chrome extension (no server, no DB).
*/
/**
* Create a LanguageModel instance from settings.
* Throws if no API key is available for the selected provider.
*/
function createModelFromSettings(settings) {
	const apiKey = settings.apiKeys[settings.provider];
	if (!apiKey && settings.provider !== "ollama") throw new Error(`No API key configured for "${settings.provider}". Add one in extension settings.`);
	switch (settings.provider) {
		case "anthropic": return createAnthropic({
			apiKey,
			headers: { "anthropic-dangerous-direct-browser-access": "true" }
		})(settings.model);
		case "openai": return createOpenAI({ apiKey })(settings.model);
		case "google": return createGoogleGenerativeAI({ apiKey })(settings.model);
		case "ollama": return createOpenAI({
			baseURL: settings.ollamaBaseUrl ?? "http://localhost:11434/v1",
			apiKey: "ollama"
		})(settings.model);
	}
}
